import{_ as t,a as e,b as o,c as r,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as i,c as s,a2 as n}from"./chunks/framework.DnrXFDHb.js";const B=JSON.parse('{"title":"Telegram 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/telegram.md","filePath":"ko-KR/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"ko-KR/upload/telegram.md"};function c(p,a,m,g,b,u){return i(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="telegram-채널-추가" tabindex="-1">Telegram 채널 추가 <a class="header-anchor" href="#telegram-채널-추가" aria-label="Permalink to &quot;Telegram 채널 추가&quot;">​</a></h1><p>Telegram 채널을 저장 위치로 사용하려면 Bot을 만들고, 그 Bot을 저장용 채널에 추가해야 합니다.</p><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>Telegram 계정</td><td>Bot과 채널 생성</td></tr><tr><td><code>@BotFather</code></td><td>Telegram Bot 생성</td></tr><tr><td>Telegram 채널</td><td>파일 저장 위치</td></tr><tr><td><code>@userinfobot</code></td><td>채널 Chat ID 확인</td></tr></tbody></table><h2 id="bot-만들기" tabindex="-1">Bot 만들기 <a class="header-anchor" href="#bot-만들기" aria-label="Permalink to &quot;Bot 만들기&quot;">​</a></h2><ol><li>Telegram에서 <code>@BotFather</code>를 검색합니다.</li><li>채팅을 열고 <code>/newbot</code>을 보냅니다.</li><li>표시 이름과 username을 입력합니다. username은 보통 <code>bot</code>으로 끝나야 합니다.</li><li>생성 후 반환되는 Token을 복사합니다.</li></ol><p><img src="'+t+'" alt="Bot Token" loading="lazy"></p><h2 id="저장용-채널-만들기" tabindex="-1">저장용 채널 만들기 <a class="header-anchor" href="#저장용-채널-만들기" aria-label="Permalink to &quot;저장용 채널 만들기&quot;">​</a></h2><p>Telegram에서 새 채널을 만듭니다. 공개 채널과 비공개 채널 모두 사용할 수 있습니다.</p><p><img src="'+e+'" alt="채널 만들기" loading="lazy"></p><h2 id="bot을-채널에-추가하기" tabindex="-1">Bot을 채널에 추가하기 <a class="header-anchor" href="#bot을-채널에-추가하기" aria-label="Permalink to &quot;Bot을 채널에 추가하기&quot;">​</a></h2><p>생성한 채널 설정에서 앞서 만든 Bot을 멤버 또는 관리자로 추가합니다.</p><p><img src="'+o+'" alt="Bot 추가" loading="lazy"></p><p>안정적인 업로드를 위해 Bot에 관리자 권한을 주는 것을 권장합니다.</p><h2 id="chat-id-가져오기" tabindex="-1">Chat ID 가져오기 <a class="header-anchor" href="#chat-id-가져오기" aria-label="Permalink to &quot;Chat ID 가져오기&quot;">​</a></h2><ol><li>Telegram에서 <code>@userinfobot</code>를 검색합니다.</li><li><code>Start</code>를 누릅니다.</li><li>Bot이 제공하는 선택지에서 <code>Channel</code>을 선택합니다.</li><li>대상 채널의 메시지를 <code>@userinfobot</code>으로 보냅니다.</li><li><code>Id: -100...</code>으로 시작하는 숫자를 복사합니다.</li></ol><p><img src="'+r+'" alt="Chat ID" loading="lazy"></p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>업로드 설정에서 <code>Telegram</code>을 선택합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>채널 이름</td><td>예: <code>Telegram Main</code></td></tr><tr><td>Bot Token</td><td><code>@BotFather</code>에서 받은 Token</td></tr><tr><td>Session ID / Chat ID</td><td><code>-100</code>으로 시작하는 채널 ID</td></tr><tr><td>Relay Proxy URL</td><td>선택 사항. Telegram 연결이 불안정할 때만 입력</td></tr><tr><td>메모</td><td>선택 사항</td></tr></tbody></table><p><img src="'+l+`" alt="Telegram 설정" loading="lazy"></p><h2 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h2><ol><li>저장 후 Telegram 채널 카드가 표시됩니다.</li><li>테스트 이미지를 업로드합니다.</li><li>대상 Telegram 채널에 파일이 올라오는지 확인합니다.</li><li>ImgBed 링크가 열리는지 확인합니다.</li></ol><h2 id="빠른-절차" tabindex="-1">빠른 절차 <a class="header-anchor" href="#빠른-절차" aria-label="Permalink to &quot;빠른 절차&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather에서 Bot 생성</span></span>
<span class="line"><span>-&gt; Bot Token 복사</span></span>
<span class="line"><span>-&gt; Telegram 채널 생성</span></span>
<span class="line"><span>-&gt; Bot을 채널에 추가하고 관리자 권한 부여</span></span>
<span class="line"><span>-&gt; @userinfobot으로 -100으로 시작하는 Chat ID 확인</span></span>
<span class="line"><span>-&gt; ImgBed에 Bot Token과 Chat ID 입력</span></span>
<span class="line"><span>-&gt; 저장 후 테스트 업로드</span></span></code></pre></div><h2 id="참고" tabindex="-1">참고 <a class="header-anchor" href="#참고" aria-label="Permalink to &quot;참고&quot;">​</a></h2><ol><li>Telegram Bot: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,27)])])}const f=d(h,[["render",c]]);export{B as __pageData,f as default};
